if (currentRoad.orientation === 'horizontal') {
  return (
    newPos.x >= Math.min(currentRoad.start, currentRoad.end) - MOVE_TOLERANCE &&
    newPos.x <= Math.max(currentRoad.start, currentRoad.end) + MOVE_TOLERANCE
  );
} else {
  // Vertical
  return (
    newPos.y >= Math.min(currentRoad.start, currentRoad.end) - MOVE_TOLERANCE &&
    newPos.y <= Math.max(currentRoad.start, currentRoad.end) + MOVE_TOLERANCE
  );
}

link
    .attr('hidden', (node: InjectorTreeD3Node) => {
      const parentId = node.parent?.data.injector.id;
      return parentId === 'N/A' ? 'true' : null;
    })
    .attr('data-id', (node: InjectorTreeD3Node) => {
      const from = node.data.injector.id;
      const to = node.parent?.data.injector.id;

      if (from && to) {
        return `${from}-to-${to}`;
      }
      return '';
    });

d3Link
      .append('title')
      .attr('id', (_, idx) => `tree-link-${instanceIdx}-${idx}`)
      .text((node: TreeD3Node<T>) => {
        const parentLabel = node.parent!.data.label;
        const nodeLabel = node.data.label;
        if (parentLabel && nodeLabel) {
          return `${parentLabel}-${nodeLabel}`;
        }
        const definedLabel = nodeLabel || parentLabel || 'Disconnected';

        return definedLabel + ' link';
      });

for (const [key, info] of Object.entries(combinedData.knownInputs)) {
  const existing = globalMeta.knownInputs[key];
  if (existing !== undefined) {
    continue;
  }

  const node: GraphNode<InputData> = {
    incoming: new Set(),
    outgoing: new Set(),
    data: {info, key},
  };
  inheritanceGraph.push(node);
  idToGraphNode.set(key, node);

  globalMeta.knownInputs[key] = info;
}

export const arrayifyProps = (
props: {[prop: string]: Descriptor} | Descriptor[],
parent: Property | null = null,
): Property[] =>
Object.entries(props)
.map(([name, val]) => ({name, descriptor: val, parent}))
.sort((a, b) => {
  const parsedA = parseInt(a.name, 10);
  const parsedB = parseInt(b.name, 10);

  if (isNaN(parsedA) || isNaN(parsedB)) {
    return a.name > b.name ? 1 : -1;
  }

  return parsedA - parsedB;
});
